import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"Plugins","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/index.md","filePath":"plugins/index.md"}`),a={name:`plugins/index.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /plugins.md for this page in Markdown format</div><h1 id="plugins" tabindex="-1">Plugins <a class="header-anchor" href="#plugins" aria-label="Permalink to “Plugins”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>Vite aims to provide out-of-the-box support for common web development patterns. Before searching for a Vite or Compatible Rollup plugin, check out the <a href="./../guide/features">Features Guide</a>. A lot of the cases where a plugin would be needed in a Rollup project are already covered in Vite.</p></div><p>Check out <a href="./../guide/using-plugins">Using Plugins</a> for information on how to use plugins.</p><h2 id="official-plugins" tabindex="-1">Official Plugins <a class="header-anchor" href="#official-plugins" aria-label="Permalink to “Official Plugins”">​</a></h2><h3 id="vitejs-plugin-vue" tabindex="-1"><a href="https://github.com/vitejs/vite-plugin-vue/tree/main/packages/plugin-vue" target="_blank" rel="noreferrer">@vitejs/plugin-vue</a> <a class="header-anchor" href="#vitejs-plugin-vue" aria-label="Permalink to “@vitejs/plugin-vue”">​</a></h3><p>Provides Vue 3 Single File Components support.</p><h3 id="vitejs-plugin-vue-jsx" tabindex="-1"><a href="https://github.com/vitejs/vite-plugin-vue/tree/main/packages/plugin-vue-jsx" target="_blank" rel="noreferrer">@vitejs/plugin-vue-jsx</a> <a class="header-anchor" href="#vitejs-plugin-vue-jsx" aria-label="Permalink to “@vitejs/plugin-vue-jsx”">​</a></h3><p>Provides Vue 3 JSX support (via <a href="https://github.com/vuejs/babel-plugin-jsx" target="_blank" rel="noreferrer">dedicated Babel transform</a>).</p><h3 id="vitejs-plugin-react" tabindex="-1"><a href="https://github.com/vitejs/vite-plugin-react/tree/main/packages/plugin-react" target="_blank" rel="noreferrer">@vitejs/plugin-react</a> <a class="header-anchor" href="#vitejs-plugin-react" aria-label="Permalink to “@vitejs/plugin-react”">​</a></h3><p>Provides React Fast Refresh support via <a href="https://oxc.rs/docs/guide/usage/transformer" target="_blank" rel="noreferrer">Oxc Transformer</a>.</p><h3 id="vitejs-plugin-react-swc" tabindex="-1"><a href="https://github.com/vitejs/vite-plugin-react/tree/main/packages/plugin-react-swc" target="_blank" rel="noreferrer">@vitejs/plugin-react-swc</a> <a class="header-anchor" href="#vitejs-plugin-react-swc" aria-label="Permalink to “@vitejs/plugin-react-swc”">​</a></h3><p>Replaces Oxc with <a href="https://swc.rs/" target="_blank" rel="noreferrer">SWC</a> during development for SWC plugin usage. During production builds, SWC+Oxc Transformer are used when using plugins. For big projects that require custom plugins, cold start and Hot Module Replacement (HMR) can be significantly faster, if the plugin is also available for SWC.</p><h3 id="vitejs-plugin-rsc" tabindex="-1"><a href="https://github.com/vitejs/vite-plugin-react/tree/main/packages/plugin-rsc" target="_blank" rel="noreferrer">@vitejs/plugin-rsc</a> <a class="header-anchor" href="#vitejs-plugin-rsc" aria-label="Permalink to “@vitejs/plugin-rsc”">​</a></h3><p>Vite supports <a href="https://react.dev/reference/rsc/server-components" target="_blank" rel="noreferrer">React Server Components (RSC)</a> through the plugin. It utilizes the <a href="/guide/api-environment">Environment API</a> to provide low-level primitives that React frameworks can use to integrate RSC features. You can try a minimal standalone RSC application with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vite@latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsc</span></span></code></pre></div><p>Read the <a href="https://github.com/vitejs/vite-plugin-react/tree/main/packages/plugin-rsc" target="_blank" rel="noreferrer">plugin documentation</a> to learn more.</p><h3 id="vitejs-plugin-legacy" tabindex="-1"><a href="https://github.com/vitejs/vite/tree/main/packages/plugin-legacy" target="_blank" rel="noreferrer">@vitejs/plugin-legacy</a> <a class="header-anchor" href="#vitejs-plugin-legacy" aria-label="Permalink to “@vitejs/plugin-legacy”">​</a></h3><p>Provides legacy browsers support for the production build.</p><h2 id="community-plugins" tabindex="-1">Community Plugins <a class="header-anchor" href="#community-plugins" aria-label="Permalink to “Community Plugins”">​</a></h2><p>Check out <a href="https://registry.vite.dev/plugins" target="_blank" rel="noreferrer">Vite Plugin Registry</a> for the list of plugins published to npm.</p><h2 id="rolldown-builtin-plugins" tabindex="-1">Rolldown Builtin Plugins <a class="header-anchor" href="#rolldown-builtin-plugins" aria-label="Permalink to “Rolldown Builtin Plugins”">​</a></h2><p>Vite uses <a href="https://rolldown.rs/" target="_blank" rel="noreferrer">Rolldown</a> under the hood and it provides a few builtin plugins for common use cases.</p><p>Read the <a href="https://rolldown.rs/builtin-plugins/" target="_blank" rel="noreferrer">Rolldown Builtin Plugins section</a> for more information.</p><h2 id="rolldown-rollup-plugins" tabindex="-1">Rolldown / Rollup Plugins <a class="header-anchor" href="#rolldown-rollup-plugins" aria-label="Permalink to “Rolldown / Rollup Plugins”">​</a></h2><p><a href="./../guide/api-plugin">Vite plugins</a> are an extension of Rollup&#39;s plugin interface. Check out the <a href="./../guide/api-plugin#rolldown-plugin-compatibility">Rollup Plugin Compatibility section</a> for more information.</p>`,26)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};